import{_ as t,c as o,o as d,ag as r}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"DAG Runtime Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-runtime/docs/SPEC.md","filePath":"packages/dag-runtime/docs/SPEC.md"}'),a={name:"packages/dag-runtime/docs/SPEC.md"};function c(n,e,i,s,u,l){return d(),o("div",null,e[0]||(e[0]=[r('<h1 id="dag-runtime-specification" tabindex="-1">DAG Runtime Specification <a class="header-anchor" href="#dag-runtime-specification" aria-label="Permalink to &quot;DAG Runtime Specification&quot;">​</a></h1><p>Package: <code>@robota-sdk/dag-runtime</code> v0.1.0</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>dag-runtime</code> owns the runtime orchestration layer for DAG execution. Its responsibilities are:</p><ul><li>Creating DAG runs from published definitions with idempotent run-key semantics.</li><li>Resolving time semantics (logical date) based on trigger type via <code>TimeSemanticsService</code> from <code>dag-core</code>.</li><li>Transitioning DAG run and task run states through <code>DagRunStateMachine</code> and <code>TaskRunStateMachine</code> from <code>dag-core</code>.</li><li>Identifying entry nodes (nodes with empty <code>dependsOn</code>) and enqueuing them as initial task runs.</li><li>Querying DAG run status along with associated task runs.</li><li>Cancelling DAG runs through state machine transition validation.</li><li>Publishing execution progress events (<code>STARTED</code>, <code>FAILED</code>) via <code>IRunProgressEventReporter</code>.</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><h3 id="depends-on" tabindex="-1">Depends on <a class="header-anchor" href="#depends-on" aria-label="Permalink to &quot;Depends on&quot;">​</a></h3><ul><li><code>@robota-sdk/dag-core</code> -- all domain types, state machines, port interfaces, error builders, time semantics, and execution progress event constants.</li></ul><h3 id="does-not-own" tabindex="-1">Does not own <a class="header-anchor" href="#does-not-own" aria-label="Permalink to &quot;Does not own&quot;">​</a></h3><ul><li><strong>Worker execution loops</strong> -- owned by <code>dag-worker</code>.</li><li><strong>Scheduler triggers</strong> -- owned by <code>dag-scheduler</code>.</li><li><strong>Storage and queue implementations</strong> -- consumed through port interfaces (<code>IStoragePort</code>, <code>IQueuePort</code>, <code>IClockPort</code>) defined in <code>dag-core</code>.</li><li><strong>API transport</strong> -- owned by <code>dag-api</code>.</li><li><strong>DAG definition authoring or validation</strong> -- owned by <code>dag-core</code> and <code>dag-designer</code>.</li><li><strong>Projection or read-model concerns</strong> -- owned by <code>dag-projection</code>.</li><li><strong>Node definition or execution logic</strong> -- owned by <code>dag-nodes</code> and <code>dag-worker</code>.</li></ul><h3 id="import-direction" tabindex="-1">Import direction <a class="header-anchor" href="#import-direction" aria-label="Permalink to &quot;Import direction&quot;">​</a></h3><p>All imports flow toward <code>dag-core</code>. This package does not import from any sibling DAG package.</p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package exposes three service classes, each with a single responsibility:</p><ol><li><strong>RunOrchestratorService</strong> -- The primary orchestration service. Accepts port dependencies via constructor injection (<code>IStoragePort</code>, <code>IQueuePort</code>, <code>IClockPort</code>, optional <code>IRunProgressEventReporter</code>). Provides three public methods: <ul><li><code>createRun</code> -- Resolves the definition, validates publication status, resolves time semantics, generates an idempotent run key, and persists a new <code>DagRun</code> in <code>created</code> status. Handles race conditions by re-querying on storage conflict.</li><li><code>startCreatedRun</code> -- Takes a <code>dagRunId</code> in <code>created</code> status, parses the definition snapshot, identifies entry nodes, transitions the run through <code>created -&gt; queued -&gt; running</code>, creates task runs for entry nodes, and enqueues queue messages. On enqueue failure, transitions the run to <code>failed</code> and all affected tasks to <code>cancelled</code>.</li><li><code>startRun</code> -- Composes <code>createRun</code> and <code>startCreatedRun</code> into a single idempotent operation. If the run already exists and is past <code>created</code>, returns existing task run IDs.</li></ul></li></ol><h3 id="behavioral-contracts" tabindex="-1">Behavioral Contracts <a class="header-anchor" href="#behavioral-contracts" aria-label="Permalink to &quot;Behavioral Contracts&quot;">​</a></h3><h4 id="entry-task-enqueue-failure-recovery" tabindex="-1">Entry Task Enqueue Failure Recovery <a class="header-anchor" href="#entry-task-enqueue-failure-recovery" aria-label="Permalink to &quot;Entry Task Enqueue Failure Recovery&quot;">​</a></h4><p>When <code>dispatchEntryTasks</code> enqueues entry tasks and one enqueue fails mid-batch:</p><ol><li>Tasks already enqueued successfully remain in the queue (no rollback of successful enqueues).</li><li>The failed task&#39;s <code>TaskRun</code> is transitioned to <code>cancelled</code> status.</li><li>All previously created <code>TaskRun</code> records (including successfully enqueued ones) are transitioned to <code>cancelled</code> status. Workers that dequeue already-enqueued messages will encounter a cancelled task and skip execution via state machine rejection.</li><li>The DAG run is transitioned to <code>failed</code> status.</li><li>A <code>FAILED</code> execution progress event is published.</li></ol><p>Entry nodes that have not yet been iterated in the dispatch loop do not have <code>TaskRun</code> records created, so no cleanup is needed for them. This means the storage may not contain a complete audit trail of all intended entry tasks — only those that were created before the failure.</p><h4 id="startcreatedrun-idempotency" tabindex="-1">startCreatedRun Idempotency <a class="header-anchor" href="#startcreatedrun-idempotency" aria-label="Permalink to &quot;startCreatedRun Idempotency&quot;">​</a></h4><p><code>startCreatedRun</code> is safe to call on a run that is already past the <code>created</code> state. If the run is in <code>queued</code>, <code>running</code>, or any terminal state, the method returns the existing task run IDs without re-enqueuing or re-transitioning. This prevents duplicate task creation on retry.</p><ol start="2"><li><p><strong>RunQueryService</strong> -- Read-only service. Accepts <code>IStoragePort</code>. Retrieves a <code>DagRun</code> and its associated <code>ITaskRun[]</code> by <code>dagRunId</code>.</p></li><li><p><strong>RunCancelService</strong> -- Accepts <code>IStoragePort</code> and <code>IClockPort</code>. Validates the cancel transition through <code>DagRunStateMachine</code> and updates run status to <code>cancelled</code>.</p></li></ol><p>All services use the <code>TResult&lt;T, IDagError&gt;</code> pattern for error handling. There are no fallback paths or silent error swallowing.</p><h3 id="run-key-idempotency" tabindex="-1">Run Key Idempotency <a class="header-anchor" href="#run-key-idempotency" aria-label="Permalink to &quot;Run Key Idempotency&quot;">​</a></h3><p>Run keys follow the format <code>{dagId}:{logicalDate}</code> or <code>{dagId}:{logicalDate}:rerun:{rerunKey}</code>. Duplicate run key detection prevents redundant DAG runs. A storage-level race condition (concurrent create) is handled by re-querying the existing run.</p><h3 id="state-transitions" tabindex="-1">State Transitions <a class="header-anchor" href="#state-transitions" aria-label="Permalink to &quot;State Transitions&quot;">​</a></h3><p>All state transitions are delegated to <code>DagRunStateMachine</code> and <code>TaskRunStateMachine</code> from <code>dag-core</code>. The orchestrator does not define or override transition rules.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Owner</th><th>Role</th></tr></thead><tbody><tr><td><code>IStartRunInput</code></td><td><code>dag-runtime</code></td><td>Input contract for <code>startRun</code> and <code>createRun</code></td></tr><tr><td><code>ICreateRunInput</code></td><td><code>dag-runtime</code></td><td>Alias of <code>IStartRunInput</code> for <code>createRun</code></td></tr><tr><td><code>ICreateRunResult</code></td><td><code>dag-runtime</code></td><td>Return value of <code>createRun</code> (includes <code>status</code>)</td></tr><tr><td><code>IStartRunResult</code></td><td><code>dag-runtime</code></td><td>Return value of <code>startRun</code> (includes <code>taskRunIds</code>)</td></tr><tr><td><code>IRunQueryResult</code></td><td><code>dag-runtime</code></td><td>Return value of <code>getRun</code> (dagRun + taskRuns)</td></tr><tr><td><code>IRunCancelResult</code></td><td><code>dag-runtime</code></td><td>Return value of <code>cancelRun</code></td></tr><tr><td><code>RunOrchestratorService</code></td><td><code>dag-runtime</code></td><td>Orchestration service class</td></tr><tr><td><code>RunQueryService</code></td><td><code>dag-runtime</code></td><td>Query service class</td></tr><tr><td><code>RunCancelService</code></td><td><code>dag-runtime</code></td><td>Cancel service class</td></tr><tr><td><code>DAG_RUNTIME_PACKAGE_NAME</code></td><td><code>dag-runtime</code></td><td>Package name constant</td></tr><tr><td><code>IDagDefinition</code></td><td><code>dag-core</code></td><td>Imported -- DAG definition structure</td></tr><tr><td><code>IDagRun</code></td><td><code>dag-core</code></td><td>Imported -- DAG run record</td></tr><tr><td><code>ITaskRun</code></td><td><code>dag-core</code></td><td>Imported -- Task run record</td></tr><tr><td><code>IDagError</code></td><td><code>dag-core</code></td><td>Imported -- Structured error type</td></tr><tr><td><code>TResult</code></td><td><code>dag-core</code></td><td>Imported -- Result monad</td></tr><tr><td><code>TDagRunStatus</code></td><td><code>dag-core</code></td><td>Imported -- Run status union</td></tr><tr><td><code>TDagTriggerType</code></td><td><code>dag-core</code></td><td>Imported -- Trigger type union</td></tr><tr><td><code>TPortPayload</code></td><td><code>dag-core</code></td><td>Imported -- Port payload type</td></tr><tr><td><code>IStoragePort</code></td><td><code>dag-core</code></td><td>Imported -- Storage port interface</td></tr><tr><td><code>IQueuePort</code></td><td><code>dag-core</code></td><td>Imported -- Queue port interface</td></tr><tr><td><code>IClockPort</code></td><td><code>dag-core</code></td><td>Imported -- Clock port interface</td></tr><tr><td><code>IQueueMessage</code></td><td><code>dag-core</code></td><td>Imported -- Queue message structure</td></tr><tr><td><code>IRunProgressEventReporter</code></td><td><code>dag-core</code></td><td>Imported -- Event reporter port</td></tr><tr><td><code>DagRunStateMachine</code></td><td><code>dag-core</code></td><td>Imported -- Run state transition logic</td></tr><tr><td><code>TaskRunStateMachine</code></td><td><code>dag-core</code></td><td>Imported -- Task state transition logic</td></tr><tr><td><code>TimeSemanticsService</code></td><td><code>dag-core</code></td><td>Imported -- Logical date resolution</td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Signature Summary</th></tr></thead><tbody><tr><td><code>RunOrchestratorService</code></td><td>Class</td><td><code>constructor(storage: IStoragePort, queue: IQueuePort, clock: IClockPort, runProgressEventReporter?: IRunProgressEventReporter)</code></td></tr><tr><td><code>RunOrchestratorService.createRun</code></td><td>Method</td><td><code>(input: ICreateRunInput) =&gt; Promise&lt;TResult&lt;ICreateRunResult, IDagError&gt;&gt;</code></td></tr><tr><td><code>RunOrchestratorService.startCreatedRun</code></td><td>Method</td><td><code>(dagRunId: string) =&gt; Promise&lt;TResult&lt;IStartRunResult, IDagError&gt;&gt;</code></td></tr><tr><td><code>RunOrchestratorService.startRun</code></td><td>Method</td><td><code>(input: IStartRunInput) =&gt; Promise&lt;TResult&lt;IStartRunResult, IDagError&gt;&gt;</code></td></tr><tr><td><code>RunQueryService</code></td><td>Class</td><td><code>constructor(storage: IStoragePort)</code></td></tr><tr><td><code>RunQueryService.getRun</code></td><td>Method</td><td><code>(dagRunId: string) =&gt; Promise&lt;TResult&lt;IRunQueryResult, IDagError&gt;&gt;</code></td></tr><tr><td><code>RunCancelService</code></td><td>Class</td><td><code>constructor(storage: IStoragePort, clock: IClockPort)</code></td></tr><tr><td><code>RunCancelService.cancelRun</code></td><td>Method</td><td><code>(dagRunId: string) =&gt; Promise&lt;TResult&lt;IRunCancelResult, IDagError&gt;&gt;</code></td></tr><tr><td><code>IStartRunInput</code></td><td>Interface</td><td><code>{ dagId, version?, trigger, logicalDate?, rerunKey?, input }</code></td></tr><tr><td><code>ICreateRunInput</code></td><td>Interface</td><td>Extends <code>IStartRunInput</code></td></tr><tr><td><code>ICreateRunResult</code></td><td>Interface</td><td><code>{ dagRunId, dagId, version, logicalDate, status }</code></td></tr><tr><td><code>IStartRunResult</code></td><td>Interface</td><td><code>{ dagRunId, dagId, version, logicalDate, taskRunIds }</code></td></tr><tr><td><code>IRunQueryResult</code></td><td>Interface</td><td><code>{ dagRun: IDagRun, taskRuns: ITaskRun[] }</code></td></tr><tr><td><code>IRunCancelResult</code></td><td>Interface</td><td><code>{ dagRunId, status: &#39;cancelled&#39; }</code></td></tr><tr><td><code>DAG_RUNTIME_PACKAGE_NAME</code></td><td>Constant</td><td><code>&#39;@robota-sdk/dag-runtime&#39;</code></td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ol><li><p><strong>Storage port</strong> -- Any implementation of <code>IStoragePort</code> can be injected. The package ships no storage implementation; tests use <code>InMemoryStoragePort</code> from <code>dag-core</code>.</p></li><li><p><strong>Queue port</strong> -- Any implementation of <code>IQueuePort</code> can be injected. Tests use <code>InMemoryQueuePort</code> from <code>dag-core</code>.</p></li><li><p><strong>Clock port</strong> -- Any implementation of <code>IClockPort</code> can be injected. Tests use <code>FakeClockPort</code> from <code>dag-core</code>.</p></li><li><p><strong>Run progress event reporter</strong> -- Optional <code>IRunProgressEventReporter</code> can be provided to the orchestrator to receive execution progress events. When omitted, no events are published.</p></li><li><p><strong>Rerun key</strong> -- The <code>rerunKey</code> field in <code>IStartRunInput</code> allows creating distinct runs for the same DAG and logical date, enabling controlled rerun semantics without colliding with the original run key.</p></li></ol><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use <code>IDagError</code> from <code>dag-core</code> and are constructed via <code>buildValidationError</code> or <code>buildDispatchError</code>.</p><h3 id="validation-errors" tabindex="-1">Validation Errors <a class="header-anchor" href="#validation-errors" aria-label="Permalink to &quot;Validation Errors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Code</th><th>Source</th><th>Condition</th></tr></thead><tbody><tr><td><code>DAG_VALIDATION_DEFINITION_NOT_FOUND</code></td><td><code>createRun</code></td><td>No published definition found for the given <code>dagId</code> (and optional <code>version</code>)</td></tr><tr><td><code>DAG_VALIDATION_DEFINITION_NOT_PUBLISHED</code></td><td><code>createRun</code></td><td>Definition exists but its status is not <code>published</code></td></tr><tr><td><code>DAG_VALIDATION_MISSING_LOGICAL_DATE</code></td><td><code>createRun</code></td><td>Scheduled trigger without a <code>logicalDate</code> (via <code>TimeSemanticsService</code>)</td></tr><tr><td><code>DAG_VALIDATION_DAG_RUN_NOT_FOUND</code></td><td><code>startCreatedRun</code>, <code>getRun</code>, <code>cancelRun</code></td><td>No <code>DagRun</code> found for the given <code>dagRunId</code></td></tr><tr><td><code>DAG_VALIDATION_DEFINITION_SNAPSHOT_MISSING</code></td><td><code>startCreatedRun</code></td><td><code>DagRun</code> record has empty or missing <code>definitionSnapshot</code></td></tr><tr><td><code>DAG_VALIDATION_DEFINITION_SNAPSHOT_INVALID</code></td><td><code>startCreatedRun</code></td><td><code>definitionSnapshot</code> fails structural parse</td></tr><tr><td><code>DAG_VALIDATION_RUN_INPUT_SNAPSHOT_INVALID</code></td><td><code>startCreatedRun</code></td><td><code>inputSnapshot</code> fails JSON object parse</td></tr><tr><td><code>DAG_VALIDATION_NO_ENTRY_NODE</code></td><td><code>startCreatedRun</code></td><td>Definition contains no nodes with empty <code>dependsOn</code></td></tr><tr><td><code>DAG_VALIDATION_PAYLOAD_INVALID</code></td><td>internal</td><td>Parsed payload is not a JSON object</td></tr><tr><td><code>DAG_VALIDATION_PAYLOAD_PARSE_FAILED</code></td><td>internal</td><td>Payload string is not valid JSON</td></tr><tr><td><code>DAG_VALIDATION_DEFINITION_SNAPSHOT_PARSE_FAILED</code></td><td>internal</td><td>Definition snapshot string is not valid JSON</td></tr></tbody></table><h3 id="dispatch-errors" tabindex="-1">Dispatch Errors <a class="header-anchor" href="#dispatch-errors" aria-label="Permalink to &quot;Dispatch Errors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Code</th><th>Source</th><th>Condition</th></tr></thead><tbody><tr><td><code>DAG_DISPATCH_DAG_RUN_CREATE_FAILED</code></td><td><code>createRun</code></td><td>Storage-level failure when creating the <code>DagRun</code> record (and no raced run found)</td></tr><tr><td><code>DAG_DISPATCH_ENQUEUE_FAILED</code></td><td><code>startCreatedRun</code></td><td>Queue <code>enqueue</code> call throws for an entry task; triggers run failure and task cancellation</td></tr></tbody></table><h3 id="state-machine-errors" tabindex="-1">State Machine Errors <a class="header-anchor" href="#state-machine-errors" aria-label="Permalink to &quot;State Machine Errors&quot;">​</a></h3><p>State transition failures (e.g., attempting to cancel a terminal run) are returned directly from <code>DagRunStateMachine.transition</code> and <code>TaskRunStateMachine.transition</code> in <code>dag-core</code>. This package does not wrap or remap those errors.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>No classes in this package use the <code>implements</code> keyword. All port dependencies are consumed via constructor injection.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Service classes are standalone (no <code>extends</code>).</p><h3 id="port-consumption-via-di" tabindex="-1">Port Consumption via DI <a class="header-anchor" href="#port-consumption-via-di" aria-label="Permalink to &quot;Port Consumption via DI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service Class</th><th>Injected Port (from dag-core)</th><th>Location</th></tr></thead><tbody><tr><td><code>RunOrchestratorService</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code>, <code>IClockPort</code>, <code>IRunProgressEventReporter</code></td><td><code>src/services/run-orchestrator-service.ts</code></td></tr><tr><td><code>RunQueryService</code></td><td><code>IStoragePort</code></td><td><code>src/services/run-query-service.ts</code></td></tr><tr><td><code>RunCancelService</code></td><td><code>IStoragePort</code>, <code>IClockPort</code></td><td><code>src/services/run-cancel-service.ts</code></td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>IStoragePort</code> (dag-core)</td><td><code>RunOrchestratorService</code>, <code>RunQueryService</code>, <code>RunCancelService</code></td><td><code>src/services/</code></td></tr><tr><td><code>IQueuePort</code> (dag-core)</td><td><code>RunOrchestratorService</code></td><td><code>src/services/run-orchestrator-service.ts</code></td></tr><tr><td><code>IClockPort</code> (dag-core)</td><td><code>RunOrchestratorService</code>, <code>RunCancelService</code></td><td><code>src/services/</code></td></tr><tr><td><code>IRunProgressEventReporter</code> (dag-core)</td><td><code>RunOrchestratorService</code></td><td><code>src/services/run-orchestrator-service.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><p>Tests are located in <code>packages/dag-runtime/src/__tests__/</code> and executed via <code>vitest</code>.</p><h3 id="test-files" tabindex="-1">Test files <a class="header-anchor" href="#test-files" aria-label="Permalink to &quot;Test files&quot;">​</a></h3><ul><li><p><code>run-orchestrator-service.test.ts</code> -- Tests for <code>RunOrchestratorService</code> covering:</p><ul><li>Successful run creation and entry task enqueue</li><li>Missing definition error</li><li>Scheduled trigger without logical date error</li><li>Idempotent duplicate run key handling</li><li>Two-phase create-then-start workflow</li><li>Idempotent <code>startCreatedRun</code> on already-running run</li><li>No-entry-node validation</li><li>Enqueue failure transitions (run to <code>failed</code>, task to <code>cancelled</code>)</li><li>Race condition handling during concurrent <code>createDagRun</code></li></ul></li><li><p><code>run-query-cancel-service.test.ts</code> -- Tests for <code>RunQueryService</code> and <code>RunCancelService</code> covering:</p><ul><li>Query of run with associated task runs</li><li>Cancel from <code>running</code> status with timestamp verification</li></ul></li></ul><h3 id="test-infrastructure" tabindex="-1">Test infrastructure <a class="header-anchor" href="#test-infrastructure" aria-label="Permalink to &quot;Test infrastructure&quot;">​</a></h3><p>All tests use in-memory fakes from <code>dag-core</code>:</p><ul><li><code>InMemoryStoragePort</code> -- in-memory storage implementation</li><li><code>InMemoryQueuePort</code> -- in-memory queue implementation</li><li><code>FakeClockPort</code> -- deterministic clock for reproducible timestamps</li></ul><p>Custom test doubles are defined locally:</p><ul><li><code>FailingQueuePort</code> -- simulates enqueue failure at a configurable call count</li><li><code>RacyDagRunStoragePort</code> -- extends <code>InMemoryStoragePort</code> to simulate storage race conditions</li></ul><h3 id="run-command" tabindex="-1">Run command <a class="header-anchor" href="#run-command" aria-label="Permalink to &quot;Run command&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @robota-sdk/dag-runtime</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div>',62)]))}const p=t(a,[["render",c]]);export{g as __pageData,p as default};
